                        <option value="O+" ${anamnesi.blood_type === 'O+' ? 'selected' : ''}>0+</option>
                        <option value="O-" ${anamnesi.blood_type === 'O-' ? 'selected' : ''}>0-</option>
                    </select>
                </div>

                <div class="form-group" style="margin-bottom:16px;">
