        let gridHtml;
        if (articles.length === 0) {
            gridHtml = `
            <div class="ec-empty" style="grid-column:1/-1;">
                <i class="ph ph-shopping-bag"></i>
                <p>Nessun articolo trovato</p>
            </div>`;
        } else {
            gridHtml = articles.map(a => this.articleCard(a)).join("");
        }

        return `
        <div class="ec-toolbar">
            <div class="ec-search">
                <i class="ph ph-magnifying-glass"></i>
                <input type="text" id="ec-search-input" placeholder="Cerca articolo..." autocomplete="off">
            </div>
            <select class="ec-filter-cat" id="ec-cat-filter">
                <option value="">Tutte le categorie</option>
                ${catsHtml}
            </select>
            <button class="btn-dash cyan" id="ec-add-btn" type="button">
                <i class="ph ph-plus"></i> Aggiungi Articolo
            </button>
        </div>
        <div class="ec-grid" id="ec-articles-grid">
            ${gridHtml}
        </div>
        `;
    },

    articleCard(a) {
        const cover = a.immagineBase64 
            ? `<img class="ec-card-img" src="${a.immagineBase64}" alt="${Utils.escapeHtml(a.nome)}" loading="lazy">` 
            : '<div class="ec-card-img-placeholder"><i class="ph ph-image"></i></div>';

        const badge = a.disponibile !== false
            ? '<span class="ec-badge-disponibile">● Disponibile</span>'
            : '<span class="ec-badge-non-disponibile">● Non Disponibile</span>';

        const priceFormat = (a.prezzo ?? 0).toLocaleString("it-IT", { minimumFractionDigits: 2 });

        return `
        <div class="ec-card" data-id="${a.id}">
            <div class="ec-card-img-wrapper">
                ${cover}
            </div>
            <div class="ec-card-body">
                <div class="ec-card-cat">${Utils.escapeHtml(a.categoria || "—")}</div>
                <div class="ec-card-name" title="${Utils.escapeHtml(a.nome)}">${Utils.escapeHtml(a.nome)}</div>
                <div class="ec-card-price">${priceFormat} €</div>
                <div class="ec-card-footer">
                    ${badge}
                    <div class="ec-card-actions">
                        <button class="ec-icon-btn ec-edit-btn" data-id="${a.id}" title="Modifica">✏️</button>
                        <button class="ec-icon-btn ec-delete-btn" data-id="${a.id}" title="Elimina">🗑️</button>
                    </div>
                </div>
            </div>
        </div>`;
    },

    importBanner() {
        return `
        <div class="ec-import-banner">
            <span class="ec-import-banner-icon">📦</span>
            <div style="flex:1; min-width:0;">
                <h3>Nessun articolo trovato</h3>
                <p>Importa i prodotti dal sito originale in un click, oppure aggiungili manualmente.</p>
            </div>
            <div style="display:flex; gap:10px; flex-shrink:0; flex-wrap:wrap;">
                <button class="btn-dash pink" id="ec-start-wizard" type="button">
                    <i class="ph ph-download-simple"></i> Importa dal Sito
                </button>
                <button class="btn-dash" id="ec-skip-import" type="button">
                    Aggiungi Manualmente
                </button>
            </div>
        </div>
        <div id="ec-wizard-area"></div>
        `;
    },

    ordersTable(orders, lastUpdateTimestamp = null) {
        let tbodyHtml;
        if (orders.length === 0) {
            tbodyHtml = '<tr><td colspan="6" style="text-align:center;padding:40px;opacity:.5;">Nessun ordine trovato</td></tr>';
        } else {
            tbodyHtml = orders.map(o => this.orderRow(o)).join("");
        }

        const lastUpdateText = lastUpdateTimestamp 
            ? "Ultimo aggiornamento: " + lastUpdateTimestamp.toLocaleTimeString("it-IT", { hour: "2-digit", minute: "2-digit" }) 
            : "";

        return `
        <div class="ec-orders-toolbar">
            <div class="ec-filter-bar">
                <button class="ec-filter-btn active" data-filter="all" type="button">Tutti (${orders.length})</button>
                <button class="ec-filter-btn" data-filter="pagato" type="button">🟢 Pagati</button>
                <button class="ec-filter-btn" data-filter="non pagato" type="button">🔴 Non Pagati</button>
                <button class="ec-filter-btn" data-filter="consegnato" type="button">🔵 Consegnati</button>
            </div>
            <button class="btn-dash" id="ec-orders-refresh" type="button" style="margin-left:auto;">
                <i class="ph ph-arrows-clockwise"></i> Aggiorna
            </button>
            <span class="ec-last-update" id="ec-last-update">${lastUpdateText}</span>
        </div>

        <div class="ec-table-wrap">
            <table class="ec-table">
                <thead>
                    <tr>
                        <th>Cliente</th>
                        <th>Articoli</th>
                        <th>Totale</th>
                        <th>Data</th>
                        <th>Stato</th>
                        <th>Cambia Stato</th>
                    </tr>
                </thead>
                <tbody id="ec-orders-tbody">
                    ${tbodyHtml}
                </tbody>
            </table>
        </div>
        `;
    },

    orderRow(ord) {
        let statoInterno = ord.statoInterno;
        if (statoInterno && statoInterno.toLowerCase() === "da definire") {
            statoInterno = null;
        }
        if (!statoInterno && ord.statoForms) {
            const sf = String(ord.statoForms).toLowerCase();
            if (sf === "pagato" || sf === "non pagato") statoInterno = sf;
        }

        const fallback = statoInterno || "da definire";
        let statusBadge = "";
        if (fallback === "pagato") statusBadge = '<span class="ec-badge-pagato">🟢 Pagato</span>';
        else if (fallback === "non pagato") statusBadge = '<span class="ec-badge-nonpagato">🔴 Non Pagato</span>';
        else if (fallback === "consegnato") statusBadge = '<span class="ec-badge-consegnato">🔵 Consegnato</span>';
        else statusBadge = '<span class="ec-badge-pending">⚪ Da definire</span>';

        const dataStr = ord.dataOrdine
            ? new Date(ord.dataOrdine).toLocaleDateString("it-IT", { day: "2-digit", month: "short", year: "numeric" })
            : "—";

        const totalStr = ord.totale > 0 
            ? ord.totale.toLocaleString("it-IT", { minimumFractionDigits: 2 }) + " €"
            : "—";

        const itemsStr = ord.articoli || 
            (ord.orderSummary ? ord.orderSummary.replace(/<[^>]+>/g, " ").replace(/\s+/g, " ").trim() : "") || "—";

        const fields = Array.isArray(ord._campiDisponibili) ? ord._campiDisponibili.join(", ") : "";
        const infoIcon = fields ? `<span title="Campi Cognito disponibili:\n${fields}" style="cursor:help;opacity:.4;font-size:11px;margin-left:4px;">ℹ</span>` : "";

        return `<tr>
            <td style="font-weight:600;">${Utils.escapeHtml(ord.nomeCliente || "—")}${infoIcon}</td>
            <td style="max-width:220px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${Utils.escapeHtml(itemsStr)}">
                ${Utils.escapeHtml(itemsStr.substring(0, 70))}${itemsStr.length > 70 ? "…" : ""}
            </td>
            <td style="font-weight:700;">${totalStr}</td>
            <td>${dataStr}</td>
            <td>${statusBadge}</td>
            <td>
                <select class="ec-stato-select" data-order-id="${Utils.escapeHtml(String(ord.id))}">
                    <option value="" ${statoInterno ? "" : "selected"}>— Imposta Stato</option>
                    <option value="pagato" ${statoInterno === "pagato" ? "selected" : ""}>🟢 Pagato</option>
                    <option value="non pagato" ${statoInterno === "non pagato" ? "selected" : ""}>🔴 Non Pagato</option>
                    <option value="consegnato" ${statoInterno === "consegnato" ? "selected" : ""}>🔵 Consegnato</option>
                </select>
            </td>
        </tr>`;
    }
};

export default EcommerceView;

/**
 * Staff View Module
 * Fusion ERP v1.1
 */

const STAFF_COLORS = ["#f472b6", "#3b82f6", "#10b981", "#f59e0b", "#8b5cf6", "#ec4899", "#0ea5e9"];

const StaffView = {
    getColor: function(name) {
        if (!name) return STAFF_COLORS[0];
        let t = 0;
        for (let a = 0; a < name.length; a++) t = name.charCodeAt(a) + ((t << 5) - t);
        return STAFF_COLORS[Math.abs(t) % STAFF_COLORS.length];
    },

    formatTeamName: function(category, name) {
        let a = (category || "").toUpperCase();
        return a.match(/^U\\d+$/) ? a.replace("U", "Under ") : a ? category + " — " + name : name || "";
    },

    fieldValue: function(label, value, valueColor = "var(--color-white)") {
        return `
            <div style="display:flex;flex-direction:column;gap:2px;">
                <span style="font-size:11px;color:var(--color-silver);text-transform:uppercase;font-weight:600;letter-spacing:0.04em;">${Utils.escapeHtml(label)}</span>
                <span style="font-size:14px;font-weight:500;color:${valueColor};">${value ? Utils.escapeHtml(String(value)) : '<span style="color:var(--color-text-muted);">—</span>'}</span>
            </div>
        `;
    },

    dashboard: function(staff, roles, isAdmin) {
        return `
            <div class="transport-dashboard">
                <div class="dash-top-bar" style="border-bottom: 1px solid rgba(255,255,255,0.05); padding-bottom: 24px; margin-bottom: 24px;">
                    <div>
                        <h1 class="dash-title">Gestione <span style="color:var(--accent-pink);">Staff</span></h1>
                        <p class="dash-subtitle">${staff.length} membro${staff.length !== 1 ? "i" : ""} nel sistema</p>
                    </div>
                    <div style="display:flex;gap:12px; flex-wrap:wrap; align-items:center;">
                        <div class="input-wrapper" style="position:relative;min-width:220px;">
                            <i class="ph ph-magnifying-glass" style="position:absolute;left:12px;top:50%;transform:translateY(-50%);color:rgba(255,255,255,0.4);font-size:16px;"></i>
                            <input type="text" id="staff-search" class="form-input" placeholder="Cerca membro staff..." style="padding-left:36px;height:42px;font-size:13px;background:rgba(255,255,255,0.05);border-color:rgba(255,255,255,0.1);color:#fff;">
                        </div>
                        ${isAdmin ? '<button class="btn-dash pink" id="new-staff-btn" type="button"><i class="ph ph-plus-circle" style="font-size:18px;"></i> NUOVO MEMBRO</button>' : ""}
                    </div>
                </div>
                <div class="dash-filters" id="staff-role-filter" style="margin-bottom:24px;">
                    <button class="dash-filter active" data-role="" type="button">Tutti</button>
                    ${roles.map(r => `<button class="dash-filter" data-role="${Utils.escapeHtml(r.toLowerCase())}" type="button">${Utils.escapeHtml(r)}</button>`).join("")}
                </div>
                <div class="dash-stat-grid" id="staff-grid">
                    ${staff.length === 0 ? Utils.emptyState("Nessun membro staff", "Aggiungi il primo membro con il pulsante in alto.") : ""}
                </div>
            </div>
        `;
    },

    staffCard: function(member, teamsList) {
        const color = StaffView.getColor(member.full_name);
        const initials = Utils.initials(member.full_name);
        const now = new Date();
        const medExpired = member.medical_cert_expires_at && new Date(member.medical_cert_expires_at) < now;

        let teamNamesStr = member.team_names || "";
        if (!teamNamesStr && member.team_season_ids && member.team_season_ids.length > 0) {
            teamNamesStr = member.team_season_ids.map(id => {
                const tr = teamsList.find(t => String(t.id) === String(id));
                return tr ? StaffView.formatTeamName(tr.category, tr.name) : "";
            }).filter(Boolean).join(", ");
        }

        return `
            <div class="dash-stat-card" style="cursor:pointer;position:relative;overflow:hidden;padding:16px;" data-staff-id="${Utils.escapeHtml(member.id)}" data-name="${Utils.escapeHtml((member.full_name || "").toLowerCase())}" data-role="${Utils.escapeHtml((member.role || "").toLowerCase())}">
                ${medExpired ? '<div style="position:absolute;top:var(--sp-2);right:var(--sp-2);width:8px;height:8px;border-radius:50%;background:var(--color-pink);box-shadow:0 0 6px var(--color-pink);"></div>' : ""}
                <div style="display:flex;align-items:flex-start;gap:var(--sp-2);">
                    <div style="width:48px;height:48px;background:${color};display:flex;align-items:center;justify-content:center;flex-shrink:0;font-family:var(--font-display);font-weight:700;font-size:1.3rem;color:#000;border-radius:8px;position:relative;overflow:hidden;">
                        ${member.photo_path ? `<img src="${member.photo_path}" style="width:100%;height:100%;object-fit:cover;position:absolute;top:0;left:0;z-index:1;">` : ""}
                        ${Utils.escapeHtml(initials)}
                    </div>
                    <div style="overflow:hidden;flex:1;">
                        <div style="font-family:var(--font-display);font-weight:700;font-size:1.1rem;">${Utils.escapeHtml(member.full_name)}</div>
                        <div style="font-size:12px;color:var(--color-text-muted);">${Utils.escapeHtml(member.role || "—")}</div>
                        <div style="font-size:12px;color:var(--color-text-muted);">${Utils.escapeHtml(teamNamesStr)}</div>
                        ${member.phone ? `<div style="font-size:12px;color:var(--color-text-muted);margin-top:2px;"><i class="ph ph-phone" style="font-size:11px;"></i> ${Utils.escapeHtml(member.phone)}</div>` : ""}
                    </div>
                </div>
            </div>
        `;
    },

    documentsTable: function(staff) {
        const today = new Date();
        const future60 = new Date(today.getTime() + 60 * 24 * 60 * 60 * 1000);
        let valid = 0, expiring = 0, expired = 0, missing = 0;

        const rows = staff.map(p => {
            let certHtml = "";
            let certDate = p.medical_cert_expires_at ? new Date(p.medical_cert_expires_at) : null;
            let isExpired = certDate && certDate < today;
            let isExpiring = certDate && !isExpired && certDate < future60;

            if (isExpired) { expired++; certHtml = '<span class="badge badge-danger">Scaduto</span>'; }
            else if (isExpiring) { expiring++; certHtml = '<span class="badge badge-warning">In scadenza</span>'; }
            else if (certDate) { valid++; certHtml = '<span class="badge badge-success">Valido</span>'; }
