    filtered.sort((a, b) => {
      const sDiff = (statusOrder[a.status] ?? 2) - (statusOrder[b.status] ?? 2);
      if (sDiff !== 0) return sDiff;
      const pDiff = (priorityOrder[a.priority] ?? 1) - (priorityOrder[b.priority] ?? 1);
      if (pDiff !== 0) return pDiff;
